class Solution {
public:
    vector<bool> friendRequests(int n, vector<vector<int>>& restrictions, vector<vector<int>>& requests) {
        vector<int> parent(n);
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
        vector<bool> result(requests.size());
        for (int i = 0; i < requests.size(); ++i) {
            int x = requests[i][0], y = requests[i][1];
            int x_root = find(parent, x), y_root = find(parent, y);
            bool valid = true;
            for (auto& r : restrictions) {
                int u = r[0], v = r[1];
                int u_root = find(parent, u), v_root = find(parent, v);
                if ((x_root == u_root && y_root == v_root) || (x_root == v_root && y_root == u_root)) {
                    valid = false;
                    break;
                }
            }
            result[i] = valid;
            if (valid) {
                parent[y_root] = x_root;
            }
        }
        return result;
    }

    int find(vector<int>& parent, int x) {
        if (parent[x] != x) {
            parent[x] = find(parent, parent[x]);
        }
        return parent[x];
    }
};
